"""
Typed exceptions for SCC - Sandboxed Claude CLI.

Error handling philosophy: "One message, one action"
- Each error has a clear user_message (what went wrong)
- Each error has a suggested_action (what to do next)
- Debug context is available with --debug flag

Exit codes:
- 0: Success
- 2: Invalid usage / bad input
- 3: Missing prerequisites (Docker, Git)
- 4: External tool failure (docker/git command failed)
- 5: Internal error (bug)
"""

import shlex
from dataclasses import dataclass, field


@dataclass
class SCCError(Exception):
    """Base error with user-friendly messaging."""

    user_message: str
    suggested_action: str = ""
    debug_context: str | None = None
    exit_code: int = 1

    def __str__(self) -> str:
        return self.user_message


@dataclass
class UsageError(SCCError):
    """Invalid usage or bad input."""

    exit_code: int = field(default=2, init=False)


@dataclass
class PrerequisiteError(SCCError):
    """Docker/Git missing or wrong version."""

    exit_code: int = field(default=3, init=False)


@dataclass
class DockerNotFoundError(PrerequisiteError):
    """Docker is not installed or not in PATH."""

    user_message: str = field(default="Docker is not installed or not in PATH")
    suggested_action: str = field(
        default="Install Docker Desktop from https://docker.com/products/docker-desktop"
    )


@dataclass
class DockerDaemonNotRunningError(PrerequisiteError):
    """Docker Desktop is installed but not running."""

    user_message: str = field(default="Docker Desktop is not running")
    suggested_action: str = field(default="Start Docker Desktop and try again")


@dataclass
class DockerVersionError(PrerequisiteError):
    """Docker version is too old for sandbox feature."""

    current_version: str = ""
    required_version: str = "4.50.0"
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Update Docker Desktop from https://docker.com/products/docker-desktop"
    )

    def __post_init__(self) -> None:
        if not self.user_message:
            self.user_message = (
                f"Docker Desktop {self.required_version}+ required for sandbox support\n"
                f"Current: {self.current_version or 'unknown'} | Required: {self.required_version}+"
            )


@dataclass
class SandboxNotAvailableError(PrerequisiteError):
    """Docker sandbox feature is not available."""

    user_message: str = field(default="Docker sandbox feature is not available")
    suggested_action: str = field(
        default=(
            "Ensure Docker Desktop 4.50+ is installed and the sandbox CLI is available. "
            "Run 'docker sandbox --help' to verify and check your PATH for Docker Desktop."
        )
    )


@dataclass
class GitNotFoundError(PrerequisiteError):
    """Git is not installed or not in PATH."""

    user_message: str = field(default="Git is not installed or not in PATH")
    suggested_action: str = field(default="Install Git from https://git-scm.com/downloads")


@dataclass
class ToolError(SCCError):
    """External tool (Docker/Git) command failed."""

    exit_code: int = field(default=4, init=False)
    command: str | None = None
    stderr: str | None = None

    def __post_init__(self) -> None:
        if self.command or self.stderr:
            parts = []
            if self.command:
                parts.append(f"Command: {self.command}")
            if self.stderr:
                parts.append(f"Error: {self.stderr}")
            self.debug_context = "\n".join(parts)


@dataclass
class WorkspaceError(ToolError):
    """Invalid workspace path or clone failed."""

    user_message: str = field(default="Workspace error")


@dataclass
class WorkspaceNotFoundError(WorkspaceError):
    """Workspace path does not exist."""

    path: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(default="Check the path exists or create the directory")

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.path:
            self.user_message = f"Workspace not found: {self.path}"


@dataclass
class NotAGitRepoError(WorkspaceError):
    """Path is not a git repository."""

    path: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(default="Initialize git with 'git init' or clone a repository")

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.path:
            self.user_message = f"Not a git repository: {self.path}"


@dataclass
class CloneError(WorkspaceError):
    """Git clone failed."""

    url: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(default="Check the repository URL and your network connection")

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.url:
            self.user_message = f"Failed to clone repository: {self.url}"


@dataclass
class GitWorktreeError(ToolError):
    """Worktree creation/cleanup failed."""

    user_message: str = field(default="Git worktree operation failed")


@dataclass
class WorktreeExistsError(GitWorktreeError):
    """Worktree already exists."""

    path: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Use existing worktree, remove it first, or choose a different name"
    )

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.path:
            self.user_message = f"Worktree already exists: {self.path}"


@dataclass
class WorktreeCreationError(GitWorktreeError):
    """Failed to create worktree."""

    name: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Check if the branch already exists or if there are uncommitted changes"
    )

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.name:
            self.user_message = f"Failed to create worktree: {self.name}"


@dataclass
class SandboxLaunchError(ToolError):
    """Docker sandbox failed to start."""

    exit_code: int = field(default=5, init=False)
    user_message: str = field(default="Failed to start Docker sandbox")
    suggested_action: str = field(
        default="Check Docker Desktop is running and has available resources"
    )

    def __post_init__(self) -> None:
        # Call parent to set debug_context from command/stderr
        super().__post_init__()
        # Always show stderr in suggested_action (don't hide behind debug flag)
        if self.stderr and self.stderr.strip():
            self.suggested_action = (
                f"{self.suggested_action}\n\nDocker error: {self.stderr.strip()}"
            )


@dataclass
class ContainerNotFoundError(ToolError):
    """Container does not exist (for resume operations)."""

    container_name: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Start a new session or check 'scc list' for available containers"
    )

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.container_name:
            self.user_message = f"Container not found: {self.container_name}"


@dataclass
class InternalError(SCCError):
    """Internal error (bug in the CLI)."""

    exit_code: int = field(default=5, init=False)
    suggested_action: str = field(
        default="Please report this issue at https://github.com/CCimen/scc/issues"
    )


@dataclass
class ConfigError(SCCError):
    """Configuration error."""

    exit_code: int = field(default=2, init=False)
    user_message: str = field(default="Configuration error")
    suggested_action: str = field(default="Run 'scc config --show' to view current configuration")


@dataclass
class ProfileNotFoundError(ConfigError):
    """Team profile not found."""

    profile_name: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(default="Run 'scc team list' to see available profiles")

    def __post_init__(self) -> None:
        if not self.user_message and self.profile_name:
            self.user_message = f"Team profile not found: {self.profile_name}"


@dataclass
class PolicyViolationError(ConfigError):
    """Security policy violation during config processing.

    Raised when a plugin or MCP server is blocked by
    organization security policies.
    """

    item: str = ""
    blocked_by: str = ""
    item_type: str = "plugin"  # Default to plugin
    user_message: str = field(default="")
    suggested_action: str = field(default="")

    def __post_init__(self) -> None:
        if not self.user_message and self.item:
            if self.blocked_by:
                self.user_message = (
                    f"Security policy violation: '{self.item}' is blocked "
                    f"by pattern '{self.blocked_by}'"
                )
            else:
                self.user_message = f"Security policy violation: '{self.item}' is blocked"

        # Generate fix-it command for suggested action (inline to keep core/ dependency-free)
        if not self.suggested_action and self.item:
            type_to_flag = {
                "plugin": "--allow-plugin",
                "mcp_server": "--allow-mcp",
            }
            flag = type_to_flag.get(self.item_type, f"--allow-{self.item_type}")
            quoted_item = shlex.quote(self.item)
            cmd = (
                "scc exceptions create --policy --id INC-... "
                f'{flag} {quoted_item} --ttl 8h --reason "..."'
            )
            self.suggested_action = f"To request a policy exception (requires PR approval): {cmd}"

"""Simple cross-platform file locking utilities."""

from __future__ import annotations

import errno
import hashlib
import os
import time
from collections.abc import Generator
from contextlib import contextmanager
from io import TextIOWrapper
from pathlib import Path
from types import ModuleType
from typing import Any

fcntl: ModuleType | None
msvcrt: ModuleType | None

try:
    import fcntl as _fcntl

    fcntl = _fcntl
except ImportError:  # pragma: no cover - Windows fallback
    fcntl = None

try:
    import msvcrt as _msvcrt

    msvcrt = _msvcrt
except ImportError:  # pragma: no cover - non-Windows fallback
    msvcrt = None

LOCK_DIR = Path(os.environ.get("XDG_CACHE_HOME", Path.home() / ".cache")) / "scc" / "locks"
DEFAULT_TIMEOUT = 5.0


def _normalize_key(key: str | Path) -> str:
    path = Path(key).expanduser()
    try:
        return str(path.resolve(strict=False))
    except OSError:
        return str(path.absolute())


def lock_path(namespace: str, key: str | Path | None = None) -> Path:
    """Return a stable lock file path for a namespace/key pair."""
    LOCK_DIR.mkdir(parents=True, exist_ok=True)
    if key is None:
        filename = f"{namespace}.lock"
    else:
        digest = hashlib.sha256(_normalize_key(key).encode()).hexdigest()[:16]
        filename = f"{namespace}-{digest}.lock"
    return LOCK_DIR / filename


def _acquire_lock(lock_file: TextIOWrapper[Any]) -> None:
    if fcntl is not None:
        fcntl.flock(lock_file.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
        return
    if msvcrt is not None:
        msvcrt.locking(lock_file.fileno(), msvcrt.LK_NBLCK, 1)
        return


def _release_lock(lock_file: TextIOWrapper[Any]) -> None:
    if fcntl is not None:
        fcntl.flock(lock_file.fileno(), fcntl.LOCK_UN)
        return
    if msvcrt is not None:
        try:
            msvcrt.locking(lock_file.fileno(), msvcrt.LK_UNLCK, 1)
        except OSError:
            pass


@contextmanager
def file_lock(
    path: Path, *, timeout: float = DEFAULT_TIMEOUT, poll: float = 0.1
) -> Generator[None, None, None]:
    """Acquire an exclusive file lock with a timeout."""
    path.parent.mkdir(parents=True, exist_ok=True)
    lock_file = path.open("a+")
    acquired = False
    start = time.monotonic()

    try:
        while True:
            try:
                _acquire_lock(lock_file)
                acquired = True
                break
            except OSError as e:
                if e.errno not in (errno.EACCES, errno.EAGAIN):
                    raise
            except BlockingIOError:
                pass

            if time.monotonic() - start >= timeout:
                raise TimeoutError(f"Timed out waiting for lock: {path}")
            time.sleep(poll)

        try:
            lock_file.seek(0)
            lock_file.truncate()
            lock_file.write(str(os.getpid()))
            lock_file.flush()
        except OSError:
            pass

        yield
    finally:
        if acquired:
            _release_lock(lock_file)
        lock_file.close()

"""Docker sandbox runtime adapter for SandboxRuntime port."""

from __future__ import annotations

from scc_cli import docker
from scc_cli.core.enums import NetworkPolicy
from scc_cli.core.network_policy import collect_proxy_env
from scc_cli.ports.models import SandboxHandle, SandboxSpec, SandboxState, SandboxStatus
from scc_cli.ports.sandbox_runtime import SandboxRuntime


def _extract_container_name(cmd: list[str]) -> str | None:
    for idx, arg in enumerate(cmd):
        if arg == "--name" and idx + 1 < len(cmd):
            return cmd[idx + 1]
        if arg.startswith("--name="):
            return arg.split("=", 1)[1]
    if cmd and cmd[-1].startswith("scc-"):
        return cmd[-1]
    return None


class DockerSandboxRuntime(SandboxRuntime):
    """SandboxRuntime backed by Docker sandbox CLI."""

    def ensure_available(self) -> None:
        docker.check_docker_available()

    def run(self, spec: SandboxSpec) -> SandboxHandle:
        docker.prepare_sandbox_volume_for_credentials()
        env_vars = dict(spec.env) if spec.env else {}
        if spec.network_policy == NetworkPolicy.WEB_EGRESS_ENFORCED.value:
            for key, value in collect_proxy_env().items():
                env_vars.setdefault(key, value)
        runtime_env = env_vars or None
        docker_cmd, _is_resume = docker.get_or_create_container(
            workspace=spec.workspace_mount.source,
            branch=None,
            profile=None,
            force_new=spec.force_new,
            continue_session=spec.continue_session,
            env_vars=runtime_env,
        )
        container_name = _extract_container_name(docker_cmd)
        plugin_settings = spec.agent_settings.content if spec.agent_settings else None
        docker.run(
            docker_cmd,
            org_config=spec.org_config,
            container_workdir=spec.workdir,
            plugin_settings=plugin_settings,
            env_vars=runtime_env,
        )
        return SandboxHandle(
            sandbox_id=container_name or "sandbox",
            name=container_name,
        )

    def resume(self, handle: SandboxHandle) -> None:
        docker.resume_container(handle.sandbox_id)

    def stop(self, handle: SandboxHandle) -> None:
        docker.stop_container(handle.sandbox_id)

    def remove(self, handle: SandboxHandle) -> None:
        docker.remove_container(handle.sandbox_id, force=True)

    def list_running(self) -> list[SandboxHandle]:
        return [
            SandboxHandle(sandbox_id=container.id, name=container.name)
            for container in docker.list_running_sandboxes()
        ]

    def status(self, handle: SandboxHandle) -> SandboxStatus:
        status = docker.get_container_status(handle.sandbox_id)
        if not status:
            return SandboxStatus(state=SandboxState.UNKNOWN)
        normalized = status.lower()
        if "up" in normalized or "running" in normalized:
            state = SandboxState.RUNNING
        elif "exited" in normalized or "stopped" in normalized:
            state = SandboxState.STOPPED
        else:
            state = SandboxState.UNKNOWN
        return SandboxStatus(state=state)

"""Network policy helpers for ordering and comparison."""

from __future__ import annotations

from collections.abc import Mapping

from .enums import NetworkPolicy

_NETWORK_POLICY_ORDER = {
    NetworkPolicy.OPEN.value: 0,
    NetworkPolicy.WEB_EGRESS_ENFORCED.value: 1,
    NetworkPolicy.LOCKED_DOWN_WEB.value: 2,
}


def policy_rank(policy: str | None) -> int:
    """Return numeric rank for policy (higher = more restrictive)."""
    if policy is None:
        return -1
    return _NETWORK_POLICY_ORDER.get(policy, -1)


def is_more_or_equal_restrictive(candidate: str, baseline: str) -> bool:
    """Return True if candidate is as or more restrictive than baseline."""
    return policy_rank(candidate) >= policy_rank(baseline)


def collect_proxy_env(env: Mapping[str, str] | None = None) -> dict[str, str]:
    """Collect proxy environment variables for container injection."""
    import os

    source = env or os.environ
    proxy_env: dict[str, str] = {}
    for key in ("HTTP_PROXY", "HTTPS_PROXY", "NO_PROXY"):
        value = source.get(key) or source.get(key.lower())
        if value:
            proxy_env[key] = value
    return proxy_env

"""Filesystem port definition for SCC adapters."""

from __future__ import annotations

from collections.abc import Iterable
from pathlib import Path
from typing import Protocol


class Filesystem(Protocol):
    """Filesystem operations required by application use cases."""

    def read_text(self, path: Path, *, encoding: str = "utf-8") -> str:
        """Read text content from a file."""

    def write_text(self, path: Path, content: str, *, encoding: str = "utf-8") -> None:
        """Write text content to a file."""

    def write_text_atomic(self, path: Path, content: str, *, encoding: str = "utf-8") -> None:
        """Write text content atomically within the target directory."""

    def exists(self, path: Path) -> bool:
        """Return True if the path exists."""

    def mkdir(self, path: Path, *, parents: bool = False, exist_ok: bool = False) -> None:
        """Create a directory."""

    def unlink(self, path: Path, *, missing_ok: bool = False) -> None:
        """Remove a file."""

    def iterdir(self, path: Path) -> Iterable[Path]:
        """Iterate directory entries."""

"""Fake SandboxRuntime for contract tests."""

from __future__ import annotations

from dataclasses import dataclass

from scc_cli.ports.models import SandboxHandle, SandboxSpec, SandboxState, SandboxStatus


@dataclass
class _SandboxRecord:
    handle: SandboxHandle
    status: SandboxStatus


class FakeSandboxRuntime:
    """In-memory sandbox runtime for tests."""

    def __init__(self) -> None:
        self._records: dict[str, _SandboxRecord] = {}
        self._counter = 0

    def ensure_available(self) -> None:
        return None

    def run(self, spec: SandboxSpec) -> SandboxHandle:
        self._counter += 1
        handle = SandboxHandle(sandbox_id=f"sandbox-{self._counter}")
        status = SandboxStatus(state=SandboxState.RUNNING)
        self._records[handle.sandbox_id] = _SandboxRecord(handle=handle, status=status)
        return handle

    def resume(self, handle: SandboxHandle) -> None:
        record = self._records.get(handle.sandbox_id)
        if record:
            record.status = SandboxStatus(state=SandboxState.RUNNING)

    def stop(self, handle: SandboxHandle) -> None:
        record = self._records.get(handle.sandbox_id)
        if record:
            record.status = SandboxStatus(state=SandboxState.STOPPED)

    def remove(self, handle: SandboxHandle) -> None:
        self._records.pop(handle.sandbox_id, None)

    def list_running(self) -> list[SandboxHandle]:
        return [
            record.handle
            for record in self._records.values()
            if record.status.state == SandboxState.RUNNING
        ]

    def status(self, handle: SandboxHandle) -> SandboxStatus:
        record = self._records.get(handle.sandbox_id)
        if record:
            return record.status
        return SandboxStatus(state=SandboxState.UNKNOWN)

"""Shared error mapping helpers for CLI output."""

from __future__ import annotations

from typing import Any

from scc_cli.core.errors import ConfigError, PolicyViolationError, PrerequisiteError, SCCError
from scc_cli.core.exit_codes import (
    EXIT_CONFIG,
    EXIT_ERROR,
    EXIT_GOVERNANCE,
    EXIT_PREREQ,
    EXIT_VALIDATION,
)


def to_exit_code(exc: Exception) -> int:
    """Map exceptions to standardized exit codes.

    This mirrors legacy json_command handling to preserve behavior.
    """
    if isinstance(exc, PolicyViolationError):
        return EXIT_GOVERNANCE
    if isinstance(exc, PrerequisiteError):
        return EXIT_PREREQ
    if isinstance(exc, ConfigError):
        return EXIT_CONFIG
    if isinstance(exc, SCCError):
        return getattr(exc, "exit_code", EXIT_ERROR)
    if "Validation" in type(exc).__name__:
        return EXIT_VALIDATION
    return EXIT_ERROR


def to_json_payload(exc: Exception) -> dict[str, Any]:
    """Return JSON-ready error data and messages."""
    error_data: dict[str, Any] = {
        "error_type": type(exc).__name__,
    }

    if isinstance(exc, SCCError):
        error_data["user_message"] = exc.user_message
        if exc.suggested_action:
            error_data["suggested_action"] = exc.suggested_action
        if exc.debug_context:
            error_data["debug_context"] = exc.debug_context
        error_message = exc.user_message
    else:
        error_message = str(exc)

    return {
        "errors": [error_message],
        "data": error_data,
    }


def to_human_message(exc: Exception) -> str:
    """Return a human-readable error message."""
    if isinstance(exc, SCCError):
        return exc.user_message
    return str(exc)

